Encapsulation with validation:
class BankAccount {
  private double bal;
  public BankAccount(double init){ bal = Math.max(0, init); }
  public void deposit(double a){ if(a>0) bal+=a; }
  public boolean withdraw(double a){ if(a>0 && a<=bal){ bal-=a; return true; } return false; }
}

